            const itemId = slot.item_id || slot.id || slot.name || null;
            const qty = Number(slot.quantity || 0) || 0;
            // 过滤掉item_id为"null"字符串或null的物品
            if (!itemId || itemId === 'null' || qty <= 0) return;
            
