            const JOURNEY_ALIASES = [GuixuConstants.LOREBOOK.ENTRIES.JOURNEY, '今生印记'];
            const PAST_ALIASES = [GuixuConstants.LOREBOOK.ENTRIES.PAST_LIVES, '前世回响'];

