        const prefs = this._getPrefs();
        if (!prefs.enabled) return;

        const chapterEvery = Math.max(1, Math.min(200, Number(prefs.chapterEverySections || 20)));
        const latestSecInner = this._getInner('节印记', full);
        const latestSecRecords = this._splitRecords(latestSecInner);
        if (latestSecRecords.length < chapterEvery) return;

        // 取前 N 节作为本次总结输入
        const toSummarize = latestSecRecords.slice(0, chapterEvery).join('\n\n');
        // 章印记记忆总结：三层 system 消息（按用户指定顺序）
        // 1) <节印记>内容（仅本次要总结的部分）
        // 2) <章印记>内容（已存在的历史章印记，用于连续性）
        // 3) 章印记总结提示词
        const existingChapterInner = this._getInner('章印记', full) || '';
        const nextChapterNo = (() => {
          try {
            const src = String(existingChapterInner || '');
            const re = /^章序号\|\s*第\s*(\d+)\s*章\s*$/gm;
            let m; let max = 0;
            while ((m = re.exec(src)) !== null) {
              const n = Number(m[1]);
              if (Number.isFinite(n)) max = Math.max(max, n);
            }
            return max + 1;
          } catch (_) {
            return 1;
          }
        })();
        const requestMessages = [
          { role: 'system', content: `下一章序号|第${nextChapterNo}章` },
          { role: 'system', content: toSummarize },
          { role: 'system', content: String(existingChapterInner || '').trim() || '（当前章印记为空）' },
          { role: 'system', content: this._replaceUserPlaceholders(prefs.chapterPrompt, prefs.userPlaceholder) }
        ];

        // 调用副API（复用既有端点逻辑）
        const res = await this._invokeAuxForMemory({ messages: requestMessages }, { hintLabel: '记忆总结：正在生成章印记…' });
        const chapterWrapped = this._extractFirstWrapped('章印记', res);
        if (!chapterWrapped) return;
        const chapterInner = this._extractInnerFromWrapped('章印记', chapterWrapped);
        if (!chapterInner) return;

