        async promptForSaveName(slotId) {
            const slotText = String(slotId || '').split('_')[1] || String(slotId || '');
            const title = '印记命名';
            const message = `请为印记位 ${slotText} 输入一个名称：`;

            // 优先使用全局统一文本弹窗（视觉与交互一致）
            if (window.GuixuMain && typeof window.GuixuMain.showTextPrompt === 'function') {
                while (true) {
                    const result = await window.GuixuMain.showTextPrompt({
                        title,
                        message,
                        defaultValue: '',
                        placeholder: '例如：突破金丹期',
                        okText: '确认',
                        cancelText: '取消',
                        multiline: false,
                        compact: true
                    });
                    if (result === null || result === undefined) return null;
                    const saveName = String(result || '').trim();
                    if (!saveName) {
                        GuixuHelpers.showTemporaryMessage('请输入印记名称');
                        continue;
                    }
                    return saveName;
                }
            }

            // 回退：浏览器 prompt
            const fallback = prompt(message, '');
            if (fallback === null) return null;
            const saveName = String(fallback || '').trim();
            if (!saveName) {
                GuixuHelpers.showTemporaryMessage('请输入印记名称');
                return null;
            }
            return saveName;
        }
