                    let top  = clientY - bodyRect.top + pad;
                    if (left + ttRect.width > bodyRect.width) left = Math.max(pad, bodyRect.width - ttRect.width - pad);
                    if (top + ttRect.height > bodyRect.height) top = Math.max(pad, bodyRect.height - ttRect.height - pad);
