          const nai = /^\d+$/.test(ai) ? parseInt(ai, 10) : ai;
          const nbi = /^\d+$/.test(bi) ? parseInt(bi, 10) : bi;
          if (nai === nbi) continue;
          if (typeof nai === 'number' && typeof nbi === 'number') return nai - nbi;
          if (typeof nai === 'number') return 1;
