          if (!center) { center = document.createElement('div'); center.className = 'qs-center'; }
          if (!right) { right = document.createElement('div'); right.className = 'qs-right'; }

          // 采集现有控件
          const btnCmd = qs.querySelector('#btn-quick-commands');
